import{_ as n,c as t,o as i,ag as r}from"./chunks/framework.TEMlu5e7.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":false,"text":"Dienstleistungen","tagline":"Von Setup und Hosting über Datenmigration bis zu Betrieb, Schulung und individueller Weiterentwicklung","image":{"src":"/images/qonnectra_logo.png","alt":"Qonnectra Logo"},"actions":[{"theme":"brand","text":"Kontakt aufnehmen","link":"/contact/"}]},"features":[{"title":"Kostenfreie Präsentation","details":"Lernen Sie Qonnectra unverbindlich kennen – online oder vor Ort. Wir zeigen Ihnen die Software in einer persönlichen Live-Demonstration und gehen auf Ihre Anwendungsfälle, Datenstrukturen und Fragen ein."},{"title":"Setup und Hosting","details":"Wir richten Qonnectra technisch für Sie ein – auf Ihrer eigenen Infrastruktur oder in einer passenden Hosting-Umgebung. Dazu gehören Installation, Grundkonfiguration, Rollen- und Rechtekonzept sowie die betriebsbereite Übergabe."},{"title":"Datenmigration","details":"Wir analysieren Ihre bestehende Netzdokumentation und übernehmen die strukturierte Aufbereitung und Migration nach Qonnectra. Dabei berücksichtigen wir GIS-Daten, CAD-Daten, Tabellen und weitere Bestandsquellen."},{"title":"Betrieb und Systembetreuung","details":"Auf Wunsch übernehmen wir den technischen Betrieb und die laufende Betreuung Ihrer Qonnectra-Umgebung. Dazu zählen Support, Fehleranalyse, Nutzerverwaltung, Backups und die Betreuung der Systemkomponenten."},{"title":"Fortführung der Netzdokumentation","details":"Wir unterstützen Sie bei der laufenden Pflege und Weiterentwicklung Ihrer Netzdokumentation. Dazu gehören Netzauskünfte, Exporte, kartographische Aufbereitungen sowie die Dokumentation von Netzerweiterungen und Neubauten."},{"title":"Schulungen und Weiterbildung","details":"Wir schulen Anwenderinnen und Anwender, Fachverantwortliche und Administratoren im praktischen Einsatz von Qonnectra. Ergänzend bieten wir Schulungen zu Netzdokumentation und QGIS an."}]},"headers":[],"relativePath":"services/index.md","filePath":"services/index.md"}'),a={name:"services/index.md"};function u(s,e,l,o,d,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<p>Neben der kostenfreien Open-Source-Software <strong>Qonnectra</strong> bieten wir umfassende Dienstleistungen für Einführung, Betrieb und Weiterentwicklung Ihrer Netzdokumentation. Ob <strong>Setup</strong>, <strong>Hosting</strong>, <strong>Migration bestehender Daten</strong>, <strong>laufende Betreuung</strong> oder <strong>Schulungen</strong>: Wir unterstützen Sie genau dort, wo Sie es brauchen – modular, praxisnah und abgestimmt auf Ihre Anforderungen.</p><div class="actions"><a class="VPButton medium brand" href="/kontakt">Kostenfreie Präsentation anfragen</a></div><div class="info custom-block"><p class="custom-block-title">So unterstützen wir Sie</p><ol><li><p><strong>Einstieg und Bedarfsklärung</strong><br> In einer kostenfreien Präsentation zeigen wir Ihnen Qonnectra im praktischen Einsatz und besprechen gemeinsam Ihre Ausgangssituation, Ziele und Anforderungen.</p></li><li><p><strong>Technische Einführung</strong><br> Wir übernehmen das Setup, richten die Plattform ein und konfigurieren die Grundlagen für den produktiven Einsatz.</p></li><li><p><strong>Datenbewertung und Migration</strong><br> Bestehende Datenbestände werden analysiert, bewertet und – wenn gewünscht – für die Nutzung in Qonnectra aufbereitet und importiert.</p></li><li><p><strong>Laufender Betrieb und Weiterentwicklung</strong><br> Nach dem Start begleiten wir Sie auf Wunsch dauerhaft weiter – mit Support, Betreuung, Schulungen und individuellen Erweiterungen.</p></li></ol></div><h2 id="setup-und-hosting" tabindex="-1">Setup und Hosting <a class="header-anchor" href="#setup-und-hosting" aria-label="Permalink to &quot;Setup und Hosting&quot;">​</a></h2><p>Wir übernehmen die technische Einrichtung von Qonnectra und schaffen die Grundlage für einen stabilen produktiven Betrieb.</p><details class="details custom-block" open=""><summary>Typische Leistungen</summary><ul><li>Installation aller benötigten Open-Source-Komponenten</li><li>Einrichtung auf kundeneigener Infrastruktur oder in einer Hosting-Umgebung</li><li>Grundkonfiguration von Rollen, Rechten und Projektstrukturen</li><li>Einrichtung von Bauteilen, Nomenklaturen und Basisparametern</li><li>Übergabe eines einsatzbereiten Systems</li></ul></details><p>Diese Leistung eignet sich für Organisationen, die Qonnectra schnell und sauber in Betrieb nehmen möchten.</p><h2 id="aufbereitung-und-migration-bestehender-daten" tabindex="-1">Aufbereitung und Migration bestehender Daten <a class="header-anchor" href="#aufbereitung-und-migration-bestehender-daten" aria-label="Permalink to &quot;Aufbereitung und Migration bestehender Daten&quot;">​</a></h2><p>Der Wechsel auf eine neue Plattform ist nur dann erfolgreich, wenn auch bestehende Daten sinnvoll übernommen werden können. Deshalb unterstützen wir Sie bei der Sichtung, Bewertung und Migration Ihrer vorhandenen Netzdokumentation.</p><details class="details custom-block" open=""><summary>Mögliche Datenquellen</summary><ul><li>GIS-Daten</li><li>CAD-Daten</li><li>CSV- und Tabellendaten</li><li>bestehende Dokumentationssysteme</li><li>weitere strukturierte oder teilstrukturierte Datenbestände</li></ul></details><details class="details custom-block" open=""><summary>Typische Leistungen</summary><ul><li>Analyse vorhandener Datenbestände</li><li>Bewertung der Datenqualität und Importfähigkeit</li><li>Abstimmung, welche Inhalte übernommen werden sollen</li><li>Aufbereitung von Geometrien, Topologien und Fachlogiken</li><li>Entwicklung eines tragfähigen Dokumentationskonzepts</li><li>Vollständiger Import der Bestandsdaten in Qonnectra</li></ul></details><p>So entsteht eine belastbare Datengrundlage für den weiteren Betrieb.</p><h2 id="betrieb-support-und-betreuung" tabindex="-1">Betrieb, Support und Betreuung <a class="header-anchor" href="#betrieb-support-und-betreuung" aria-label="Permalink to &quot;Betrieb, Support und Betreuung&quot;">​</a></h2><p>Auch nach der Einführung unterstützen wir Sie beim zuverlässigen Betrieb Ihrer Qonnectra-Umgebung.</p><details class="details custom-block" open=""><summary>Leistungen im laufenden Betrieb:</summary><ul><li>Betreuung der Qonnectra-Systemkomponenten</li><li>Unterstützung bei Fehlermeldungen und Störungen</li><li>Nutzer- und Rechteverwaltung</li><li>Backup-Konzepte und organisatorische Betriebssicherheit</li><li>Nachvollziehbarkeit und Begleitung von Änderungen an Datenbeständen</li><li>persönliche Unterstützung im Rahmen von Support und Hotline</li></ul></details><p>Je nach Bedarf kann die Betreuung projektbezogen, stundenweise oder im Rahmen einer dauerhaften Vereinbarung erfolgen.</p><h2 id="fortfuhrung-ihrer-netzdokumentation" tabindex="-1">Fortführung Ihrer Netzdokumentation <a class="header-anchor" href="#fortfuhrung-ihrer-netzdokumentation" aria-label="Permalink to &quot;Fortführung Ihrer Netzdokumentation&quot;">​</a></h2><p>Auf Wunsch unterstützen wir Sie nicht nur technisch, sondern auch fachlich bei der laufenden Pflege Ihrer Netzdokumentation.</p><details class="details custom-block" open=""><summary>Beispiele</summary><ul><li>Fortführung von Netzerweiterungen und Neubauten</li><li>Erstellung von Netzauskünften</li><li>Export von Daten für interne oder externe Zwecke</li><li>kartographische Visualisierungen</li><li>Unterstützung bei dokumentationsbezogenen Anfragen Dritter</li></ul></details><p>Damit bleibt Ihre Dokumentation aktuell, konsistent und nutzbar.</p><h2 id="individuelle-erweiterungen" tabindex="-1">Individuelle Erweiterungen <a class="header-anchor" href="#individuelle-erweiterungen" aria-label="Permalink to &quot;Individuelle Erweiterungen&quot;">​</a></h2><p>Qonnectra kann an spezifische Anforderungen angepasst und funktional erweitert werden.</p><p>Wir entwickeln bei Bedarf zusätzliche Features, Schnittstellen oder Workflows, die über die Standardfunktionen hinausgehen.</p><details class="details custom-block" open=""><summary>Beispiele für individuelle Leistungen</summary><ul><li>zusätzliche Softwarefunktionen</li><li>projektspezifische Workflows</li><li>Schnittstellen zu Drittsystemen</li><li>fachliche Erweiterungen für besondere Anforderungen</li></ul></details><p>So lässt sich Qonnectra passgenau in bestehende Prozesse integrieren.</p><h2 id="schulungen" tabindex="-1">Schulungen <a class="header-anchor" href="#schulungen" aria-label="Permalink to &quot;Schulungen&quot;">​</a></h2><p>Damit Ihr Team sicher mit Qonnectra arbeiten kann, bieten wir praxisnahe Schulungen für unterschiedliche Zielgruppen an.</p><details class="details custom-block" open=""><summary>Mögliche Formate</summary><ul><li>Qonnectra-Grundlagenschulungen</li><li>rollenbasierte Schulungen für Planung, Dokumentation und Administration</li><li>Schulungen zu einzelnen Workflows</li><li>Grundlagen der Netzdokumentation</li><li>QGIS-Schulungen</li><li>QGIS im Zusammenspiel mit Qonnectra</li></ul></details><p>Das <a href="/Qonnectra-docs/pr-6/manual/">Softwarehandbuch</a> steht kostenfrei zur Verfügung. Ergänzend helfen Schulungen dabei, Prozesse schneller und sicherer in die Praxis zu überführen.</p><h2 id="fur-wen-sich-unsere-dienstleistungen-eignen" tabindex="-1">Für wen sich unsere Dienstleistungen eignen <a class="header-anchor" href="#fur-wen-sich-unsere-dienstleistungen-eignen" aria-label="Permalink to &quot;Für wen sich unsere Dienstleistungen eignen&quot;">​</a></h2><p>Unsere Dienstleistungen richten sich an Organisationen, die Qonnectra professionell einführen, bestehende Daten übernehmen oder den Betrieb dauerhaft absichern möchten.</p><p>Besonders relevant sind unsere Leistungen für:</p><ul><li>Netzbetreiber</li><li>Planungs- und Ingenieurbüros</li><li>kommunale und regionale Infrastrukturakteure</li><li>Organisationen mit gewachsenen Bestandsdaten und Migrationsbedarf</li></ul><h2 id="kostenfreie-prasentation-anfragen" tabindex="-1">Kostenfreie Präsentation anfragen <a class="header-anchor" href="#kostenfreie-prasentation-anfragen" aria-label="Permalink to &quot;Kostenfreie Präsentation anfragen&quot;">​</a></h2><p>Sie möchten Qonnectra kennenlernen oder prüfen, wie sich Ihre bestehende Netzdokumentation in Qonnectra überführen lässt?</p><p>Wir zeigen Ihnen die Software gerne in einer <strong>kostenfreien persönlichen Präsentation</strong> und besprechen mit Ihnen passende nächste Schritte.</p><div class="actions"><a class="VPButton medium brand" href="/kontakt">Jetzt Präsentation anfragen</a></div>',37)])])}const m=n(a,[["render",u]]);export{c as __pageData,m as default};
